#include <bits/stdc++.h>
using namespace std;
struct Edge{
    int u,v,w;
}edge[20004];
int n,f[20004],s[20004];
int find_father(int x){
    return (f[x]==x? x:f[x]=find_father(f[x]));
}
bool cmp(Edge a,Edge b){
    return a.w<b.w;
}
int main(){
    int t;
    cin>>t;
    while(t--){
        cin>>n;
        for(int i=1;i<=n;i++)
            f[i]=i,s[i]=1;
        for(int i=1;i<n;i++)
            cin>>edge[i].u>>edge[i].v>>edge[i].w;
        sort(edge+1,edge+n,cmp);
        long long ans=0;
        for(int i=1;i<n;i++){
            int fu=find_father(edge[i].u),fv=find_father(edge[i].v);
            ans+=1LL*(s[fu]*s[fv]-1)*(edge[i].w+1);
            f[fv]=fu;
            s[fu]+=s[fv];
        }
        cout<<ans<<endl;
    }
    return 0;
}
